-- ============================================
-- FEPA Cobranzas — Esquema de base de datos
-- Ejecutar en Supabase SQL Editor
-- ============================================

-- ── TABLA CLIENTES ──
CREATE TABLE IF NOT EXISTS clientes (
  id           BIGINT PRIMARY KEY,
  nombre       TEXT NOT NULL,
  mail         TEXT DEFAULT '',
  tel          TEXT DEFAULT '',
  provincia    TEXT DEFAULT '',
  zona         TEXT DEFAULT '',
  ciudad       TEXT DEFAULT '',
  vendedor     TEXT DEFAULT '',
  deuda        NUMERIC(14,2) DEFAULT 0,
  dias_deuda   INT DEFAULT 0,
  ultimo_contacto DATE,
  tipo_acuerdo TEXT DEFAULT '',
  facturacion  TEXT DEFAULT '',
  cuit         TEXT DEFAULT '',
  cond_iva     TEXT DEFAULT '',
  notas        TEXT DEFAULT '',
  ctb_id       BIGINT,
  created_at   TIMESTAMPTZ DEFAULT NOW(),
  updated_at   TIMESTAMPTZ DEFAULT NOW()
);

-- ── TABLA FACTURAS ──
CREATE TABLE IF NOT EXISTS facturas (
  id             BIGINT PRIMARY KEY,
  cliente_id     BIGINT REFERENCES clientes(id) ON DELETE SET NULL,
  cliente_nombre TEXT DEFAULT '',
  nro            TEXT DEFAULT '',
  importe        NUMERIC(14,2) DEFAULT 0,
  fecha          DATE,
  vto            DATE,
  estado         TEXT DEFAULT 'pendiente' CHECK (estado IN ('pendiente','pagada','vencida')),
  obs            TEXT DEFAULT '',
  ctb_id         BIGINT,
  cond_venta     TEXT DEFAULT '',
  created_at     TIMESTAMPTZ DEFAULT NOW(),
  updated_at     TIMESTAMPTZ DEFAULT NOW()
);

-- ── TABLA ORDENES DE VENTA ──
CREATE TABLE IF NOT EXISTS ordenes (
  id             BIGSERIAL PRIMARY KEY,
  cliente_id     BIGINT REFERENCES clientes(id) ON DELETE SET NULL,
  cliente_nombre TEXT DEFAULT '',
  nro            TEXT DEFAULT '',
  importe        NUMERIC(14,2) DEFAULT 0,
  fecha          DATE,
  vto            DATE,
  estado         TEXT DEFAULT 'pendiente',
  obs            TEXT DEFAULT '',
  created_at     TIMESTAMPTZ DEFAULT NOW()
);

-- ── TABLA FACTURAS RECIBIDAS (facturas_v) ──
CREATE TABLE IF NOT EXISTS facturas_recibidas (
  id             BIGSERIAL PRIMARY KEY,
  proveedor      TEXT DEFAULT '',
  nro            TEXT DEFAULT '',
  importe        NUMERIC(14,2) DEFAULT 0,
  fecha          DATE,
  vto            DATE,
  estado         TEXT DEFAULT 'pendiente',
  obs            TEXT DEFAULT '',
  created_at     TIMESTAMPTZ DEFAULT NOW()
);

-- ── TABLA NOTAS ──
CREATE TABLE IF NOT EXISTS notas (
  id          BIGSERIAL PRIMARY KEY,
  cliente_id  BIGINT REFERENCES clientes(id) ON DELETE CASCADE,
  texto       TEXT DEFAULT '',
  created_at  TIMESTAMPTZ DEFAULT NOW()
);

-- ── ÍNDICES ──
CREATE INDEX IF NOT EXISTS idx_facturas_cliente ON facturas(cliente_id);
CREATE INDEX IF NOT EXISTS idx_facturas_estado  ON facturas(estado);
CREATE INDEX IF NOT EXISTS idx_facturas_vto     ON facturas(vto);
CREATE INDEX IF NOT EXISTS idx_clientes_zona    ON clientes(zona);
CREATE INDEX IF NOT EXISTS idx_clientes_deuda   ON clientes(deuda);

-- ── ROW LEVEL SECURITY (permiso público de lectura/escritura para la app) ──
ALTER TABLE clientes           ENABLE ROW LEVEL SECURITY;
ALTER TABLE facturas           ENABLE ROW LEVEL SECURITY;
ALTER TABLE ordenes            ENABLE ROW LEVEL SECURITY;
ALTER TABLE facturas_recibidas ENABLE ROW LEVEL SECURITY;
ALTER TABLE notas              ENABLE ROW LEVEL SECURITY;

-- Políticas: acceso total con anon key (podés restringir después con auth)
CREATE POLICY "acceso_total" ON clientes           FOR ALL USING (true) WITH CHECK (true);
CREATE POLICY "acceso_total" ON facturas           FOR ALL USING (true) WITH CHECK (true);
CREATE POLICY "acceso_total" ON ordenes            FOR ALL USING (true) WITH CHECK (true);
CREATE POLICY "acceso_total" ON facturas_recibidas FOR ALL USING (true) WITH CHECK (true);
CREATE POLICY "acceso_total" ON notas              FOR ALL USING (true) WITH CHECK (true);


